   200→    double hi = 100.0;
   201→    int nsteps = 100;
   202→    double step = hi / (double)nsteps;
   203→
   204→    /* [0, 100] */
   205→    for (int i = 0; i <= nsteps; i++)
   206→        emit((double)i * step);
   207→
   208→    /* [-100, 0] */
   209→    for (int i = 0; i <= nsteps; i++)
   210→        emit(-hi + (double)i * step);
   211→}
